/**
 * Single source of truth for the app's "local day / local now" (story 169).
 *
 * The app deliberately works in *local-day* buckets (see development_principles
 * — Temporal-over-Date). Historically that local day was hardcoded to
 * `Europe/Amsterdam` in ~a dozen places, plus a handful of bare
 * `Temporal.Now.plainDateISO()` calls that silently follow whatever machine
 * runs them. At home all three agree; while the user travels they diverge.
 *
 * These helpers concentrate the projection in one place. The *instant* is
 * always true (UTC under the hood); a timezone only changes how that instant
 * is presented as a wall-clock time and calendar date. Callers supply the zone
 * — the PWA from the resolved device/effective zone, the server from the
 * synced `app.timezone` setting — so neither runtime hardcodes a literal.
 */

/** Fallback zone when no `app.timezone` setting is present (the historical default). */
export const DEFAULT_APP_TIME_ZONE = 'Europe/Amsterdam';

/** Synced `settings` key holding the effective IANA zone the app should use. */
export const APP_TIMEZONE_KEY = 'app.timezone';

/**
 * Synced `settings` key holding the PWA's timezone mode: `'device'` (follow the
 * device's IANA zone, the default) or `'fixed'` (pin `APP_TIMEZONE_KEY`).
 * Server tasks ignore the mode — they only read the effective zone.
 */
export const APP_TIMEZONE_MODE_KEY = 'app.timezone.mode';

export type AppTimeZoneMode = 'device' | 'fixed';

/** Resolve a stored setting value (possibly null/empty/invalid) to a usable IANA zone. */
export function resolveAppTimeZone(setting?: string | null): string {
    const candidate = setting?.trim();
    if (!candidate) return DEFAULT_APP_TIME_ZONE;
    if (!isValidTimeZone(candidate)) return DEFAULT_APP_TIME_ZONE;
    return candidate;
}

/** True if `tz` is an IANA zone Temporal accepts. */
export function isValidTimeZone(tz: string): boolean {
    try {
        Temporal.Now.zonedDateTimeISO(tz);
        return true;
    } catch {
        return false;
    }
}

/** The current instant projected into `tz`. */
export function appNow(tz: string): Temporal.ZonedDateTime {
    return Temporal.Now.zonedDateTimeISO(tz);
}

/** Today's calendar date in `tz` as a `YYYY-MM-DD` string. */
export function appToday(tz: string): string {
    return appNow(tz).toPlainDate().toString();
}
