import type { DbDriver } from '@motivation/shared';
import {
    APP_TIMEZONE_KEY,
    APP_TIMEZONE_MODE_KEY,
    type AppTimeZoneMode,
    appNow,
    appToday,
    resolveAppTimeZone,
} from '@motivation/shared';
import { DbService } from '../db/db.service.js';

/**
 * Story 169 — the PWA's view of the app's effective timezone.
 *
 * The effective zone is cached in memory so synchronous date logic
 * (`getDefaultMealType`, `appToday(...)` in components) can read it without an
 * async DB hop. The cache defaults to the *device* zone (`Temporal.Now
 * .timeZoneId()`), which is already correct for the common "follow device"
 * case even before `initAppTimeZone()` runs.
 *
 * Persistence lives in two synced `settings` rows:
 *  - `app.timezone.mode`  — 'device' (follow the device) | 'fixed' (pinned)
 *  - `app.timezone`       — the effective IANA zone the server tasks read
 *
 * In 'device' mode the PWA keeps `app.timezone` equal to the device zone, so
 * when the user travels the change syncs to the server and notifications
 * follow them. In 'fixed' mode the stored zone is authoritative and the device
 * zone is ignored.
 */

const SETTINGS_UPSERT = `INSERT INTO settings (key, value) VALUES (?, ?)
                 ON CONFLICT(key) DO UPDATE SET value = excluded.value, updated_at = datetime('now')`;

export interface AppTimeZoneServiceDeps {
    driver?: () => Promise<DbDriver>;
    /** Device IANA zone source — injectable for tests. */
    deviceZone?: () => string;
}

async function defaultDriver(): Promise<DbDriver> {
    const service = DbService.getInstance();
    await service.init();
    return service.driver;
}

function defaultDeviceZone(): string {
    return Temporal.Now.timeZoneId();
}

export class AppTimeZoneService {
    private readonly driverFn: () => Promise<DbDriver>;
    private readonly deviceZoneFn: () => string;
    private effectiveZone: string;

    constructor(deps: AppTimeZoneServiceDeps = {}) {
        this.driverFn = deps.driver ?? defaultDriver;
        this.deviceZoneFn = deps.deviceZone ?? defaultDeviceZone;
        this.effectiveZone = this.deviceZoneFn();
    }

    /** Synchronous accessor for date logic. Cached; safe to call before init(). */
    getTimeZone(): string {
        return this.effectiveZone;
    }

    /**
     * Reconcile the cached/persisted zone on boot. In 'device' mode (default)
     * the device zone wins and is persisted if it changed (so the server
     * learns the user's current location). In 'fixed' mode the stored zone is
     * used as-is.
     */
    async init(): Promise<void> {
        const driver = await this.driverFn();
        const [mode, stored] = await Promise.all([
            this.read(driver, APP_TIMEZONE_MODE_KEY),
            this.read(driver, APP_TIMEZONE_KEY),
        ]);

        if (mode === 'fixed') {
            this.effectiveZone = resolveAppTimeZone(stored);
            return;
        }

        // 'device' (or unset) — follow the device, persist when it changed.
        const device = this.deviceZoneFn();
        this.effectiveZone = device;
        if (stored !== device) {
            await driver.execute(SETTINGS_UPSERT, APP_TIMEZONE_KEY, device);
        }
    }

    /** Switch to following the device zone and persist it immediately. */
    async followDevice(): Promise<void> {
        const driver = await this.driverFn();
        const device = this.deviceZoneFn();
        this.effectiveZone = device;
        await driver.execute(SETTINGS_UPSERT, APP_TIMEZONE_MODE_KEY, 'device');
        await driver.execute(SETTINGS_UPSERT, APP_TIMEZONE_KEY, device);
    }

    /** Pin a fixed IANA zone (falls back to the default if unparseable). */
    async pinZone(zone: string): Promise<void> {
        const driver = await this.driverFn();
        const resolved = resolveAppTimeZone(zone);
        this.effectiveZone = resolved;
        await driver.execute(SETTINGS_UPSERT, APP_TIMEZONE_MODE_KEY, 'fixed');
        await driver.execute(SETTINGS_UPSERT, APP_TIMEZONE_KEY, resolved);
    }

    async getMode(): Promise<AppTimeZoneMode> {
        const driver = await this.driverFn();
        return (await this.read(driver, APP_TIMEZONE_MODE_KEY)) === 'fixed' ? 'fixed' : 'device';
    }

    private async read(driver: DbDriver, key: string): Promise<string | null> {
        const rows = await driver.query<{ value: string }>('SELECT value FROM settings WHERE key = ?', key);
        return rows[0]?.value ?? null;
    }
}

export const appTimeZoneService = new AppTimeZoneService();

/** Synchronous effective-zone accessor for date logic across the PWA. */
export function getAppTimeZone(): string {
    return appTimeZoneService.getTimeZone();
}

/** Today in the effective app zone as a `YYYY-MM-DD` string. */
export function appTodayString(): string {
    return appToday(getAppTimeZone());
}

/** Today in the effective app zone as a `Temporal.PlainDate`. */
export function appTodayPlainDate(): Temporal.PlainDate {
    return appNow(getAppTimeZone()).toPlainDate();
}

/** Boot hook — call once after the local DB is ready. */
export function initAppTimeZone(): Promise<void> {
    return appTimeZoneService.init();
}
